import{_ as a,o as r,c as p,a5 as o}from"./chunks/framework.B5tqjWbr.js";const h=JSON.parse('{"title":"教程 0035：UPS 参数保存与默认值恢复","description":"","frontmatter":{"title":"教程 0035：UPS 参数保存与默认值恢复","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0035-ups-parameter-storage.html","status":"learning","visibility":"public","summary":"Imported from 0035-ups-parameter-storage.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0035-ups-parameter-storage.md","filePath":"content/power/lessons/0035-ups-parameter-storage.md","lastUpdated":null}'),t={name:"content/power/lessons/0035-ups-parameter-storage.md"};function l(i,e,s,d,c,n){return r(),p("div",null,[...e[0]||(e[0]=[o(`<h1 id="教程-0035-ups-参数保存与默认值恢复" tabindex="-1">教程 0035：UPS 参数保存与默认值恢复 <a class="header-anchor" href="#教程-0035-ups-参数保存与默认值恢复" aria-label="Permalink to &quot;教程 0035：UPS 参数保存与默认值恢复&quot;">​</a></h1><p>中文主讲。一个概念：保存参数时要同时保存版本、有效标志和校验和，加载失败时必须回默认值。</p><pre><code>目录
</code></pre><ul><li><p>它是什么</p></li><li><p>为什么 UPS 需要它</p></li><li><p>物理直觉</p></li><li><p>数学形式</p></li><li><p>一个仿真任务与仿真观察</p></li><li><p>固件落地</p></li><li><p>常见误解</p></li><li><p>验收标准、复盘问题、导师问题</p></li></ul><p>**保密边界：**本节只使用教学非易失存储记录，不包含公司内部NVM格式、Flash 地址、客户项目参数、未公开产品阈值或内部校验算法。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>非易失存储（non-volatile memory / NVM）是在断电后仍能保留数据的存储区域。参数保存是把参数表（parameter table）的当前值写入 NVM；默认值恢复（default restore）是在存储记录无效、版本不匹配或校验失败时回到安全的默认参数。</p><p>校验和（checksum）是用一组数据计算出的简短校验值，用来判断存储内容是否被破坏。本课只讲一个概念：保存参数时要同时保存版本、有效标志和校验和，加载失败时必须回默认值。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>上一节讲参数访问（parameter access）：通信可以改某些可写参数。但写入 RAM 后，如果掉电不保存，下次上电就丢失；如果保存内容损坏还盲目使用，保护阈值或控制参数可能变得不可预期。</p><p>UPS 上电时必须知道当前使用的参数来自哪里：是默认值，还是通过校验的已保存参数。这个来源本身就是调试和导师复盘的重要证据。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>参数保存像把调好的旋钮位置写进笔记本；校验和像笔记本最后的核对签名。下次开机先检查签名，如果签名对，就按笔记本恢复；如果签名不对，就不要相信这页纸，回到出厂默认值。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>save(parameters): record.version = 1 record.valid = 1 record.parameters = parameters record.checksum = checksum(version, parameters)</p><p>load(record): if record.valid and record.checksum == checksum(record.version, record.parameters): return record.parameters, loaded_default = 0</p><pre><code>return default_parameters, loaded_default = 1
</code></pre><p>本课的 checksum 是教学用简化计算，不代表真实产品算法。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行 Python 仿真：</p><p>cd E:\\gitee_CodeStorage\\学习\\电源 python simulations\\python\\ups_parameter_storage.py</p><p>只保存图片、不自动打开：</p><p>python simulations\\python\\ups_parameter_storage.py --no-open</p><pre><code>产物
</code></pre><ul><li><p><code>simulations/results/ups_parameter_storage.png</code></p></li><li><p>终端输出：有效加载是否使用保存值、损坏加载是否使用默认值、校验失败次数。</p></li><li><p>图内包含参数框、图例、参数值、校验状态、损坏记录和是否加载默认值。</p></li></ul><p>观察顺序：先看保存值为 170 V；再看正常加载仍为 170 V；最后看校验损坏后加载默认值 180 V。</p><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><ul><li><p><code>UpsParameterStorageRecord</code>：教学 NVM 记录，包含版本号、有效标志、校验和和参数快照。</p></li><li><p><code>version</code>：参数格式版本。</p></li><li><p><code>valid</code>：记录是否被认为有效。</p></li><li><p><code>checksum</code>：参数记录校验值。</p></li><li><p><code>UpsParameterStorage_Save()</code>：把当前参数打包成存储记录。</p></li><li><p><code>UpsParameterStorage_LoadOrDefault()</code>：校验记录，成功则加载保存值，失败则加载默认值。</p></li><li><p><code>loaded_default</code>：说明本次加载是否回到默认值。</p></li><li><p><code>checksum_ok</code>：说明本次校验是否通过。</p></li></ul><p>真实工程还会涉及 Flash 扇区擦写、磨损均衡、双备份、掉电中断保护、参数版本迁移和恢复默认值命令。本课只训练阅读主线。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>**误解：**参数写成功就等于永久保存。 **纠正：**RAM 写成功和 NVM 保存成功是两件事。</p></li><li><p>**误解：**NVM 里有数据就可以直接用。 **纠正：**必须检查有效标志、版本和校验和。</p></li><li><p>**误解：**可以把导师给的真实 NVM 记录格式写进学习仓库。 **纠正：**不能记录公司内部NVM格式，只能记录通用字段和阅读问题。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li><p>能运行 <code>python simulations\\python\\ups_parameter_storage.py --no-open</code> 并打开 <code>simulations/results/ups_parameter_storage.png</code>。</p></li><li><p>能解释 NVM、校验和、版本号、有效标志和默认值恢复分别解决什么问题。</p></li><li><p>能解释为什么校验失败时不能继续使用保存值。</p></li><li><p>能编译并运行 <code>projects/03-ups-c-firmware-skeleton</code>，看到 <code>parameter_storage</code> 输出。</p></li><li><p>能基于 <code>parameter_storage.c -&gt; UpsParameterStorage_LoadOrDefault()</code> 准备导师问题。</p></li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li><p>为什么 RAM 参数写成功不等于参数已经永久保存？</p></li><li><p>为什么校验失败时回默认值通常比继续使用损坏值更安全？</p></li><li><p>如果恢复默认值，通信上报里应该只报当前参数，还是也报“本次加载使用默认值”？</p></li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li><p>我用 <code>parameter_storage.c -&gt; UpsParameterStorage_LoadOrDefault()</code> 在校验失败时回默认值。真实工程里通常还会检查哪些通用字段？</p></li><li><p>我用 <code>simulations/results/ups_parameter_storage.png</code> 看到损坏记录会恢复 180 V 默认值。真实工程中恢复默认值后会不会记录日志或上报告警？</p></li><li><p>我不会记录公司内部NVM格式，只想确认阅读方式：看真实工程时，应先看参数版本、校验算法、双备份策略，还是恢复默认值入口？</p></li></ul><p>**下一步：**可以继续补“参数保存触发策略”，训练什么时候保存、如何避免频繁擦写、保存失败如何上报。</p><p>关联：<a href="./0034-ups-parameter-access.html">上一节：参数访问边界</a>；源稿：<code>concepts/embedded/ups-parameter-storage.md</code>；仿真：<code>simulations/python/ups_parameter_storage.py</code>。</p><pre><code>上一节：教程 0034：UPS 参数访问边界
下一节：教程 0036：UPS 参数保存触发策略
</code></pre>`,40)])])}const m=a(t,[["render",l]]);export{h as __pageData,m as default};
